import React, { createContext, useState, useEffect, useContext } from 'react';
import { ActivityIndicator, View, StyleSheet, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { Button, Text, TextInput } from 'react-native'; // Basic UI components

// --- Auth Context ---
export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);

  const STORAGE_KEY_TOKEN = 'userToken';
  const STORAGE_KEY_USER_DATA = 'userData';

  const signIn = async (username, password) => {
    // Simulate API call
    setIsLoading(true);
    try {
      // In a real app, you'd send credentials to a backend and get a token/user data
      // For MVP, just simulate success for any input
      if (username && password) {
        const token = 'mock-auth-token-123'; // Replace with actual token from API
        const user = { id: '1', username: username, email: `${username}@example.com` }; // Replace with actual user data from API

        await AsyncStorage.setItem(STORAGE_KEY_TOKEN, token);
        await AsyncStorage.setItem(STORAGE_KEY_USER_DATA, JSON.stringify(user));

        setUserToken(token);
        setUserData(user);
        Alert.alert('Success', 'Logged in successfully!');
      } else {
        Alert.alert('Error', 'Username and password are required.');
      }
    } catch (e) {
      console.error('Login error:', e);
      Alert.alert('Error', 'Failed to log in. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const signUp = async (username, email, password) => {
    // Simulate API call
    setIsLoading(true);
    try {
      // In a real app, you'd send registration data to a backend
      // For MVP, just simulate success
      if (username && email && password) {
        const token = 'mock-auth-token-456'; // Replace with actual token from API
        const user = { id: '2', username: username, email: email }; // Replace with actual user data from API

        await AsyncStorage.setItem(STORAGE_KEY_TOKEN, token);
        await AsyncStorage.setItem(STORAGE_KEY_USER_DATA, JSON.stringify(user));

        setUserToken(token);
        setUserData(user);
        Alert.alert('Success', 'Account created and logged in!');
      } else {
        Alert.alert('Error', 'All fields are required.');
      }
    } catch (e) {
      console.error('Registration error:', e);
      Alert.alert('Error', 'Failed to register. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const signOut = async () => {
    setIsLoading(true);
    try {
      await AsyncStorage.removeItem(STORAGE_KEY_TOKEN);
      await AsyncStorage.removeItem(STORAGE_KEY_USER_DATA);
      setUserToken(null);
      setUserData(null);
      Alert.alert('Info', 'Logged out successfully!');
    } catch (e) {
      console.error('Logout error:', e);
      Alert.alert('Error', 'Failed to log out. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const loadStoredData = async () => {
      let token = null;
      let user = null;
      try {
        token = await AsyncStorage.getItem(STORAGE_KEY_TOKEN);
        const userDataString = await AsyncStorage.getItem(STORAGE_KEY_USER_DATA);
        if (userDataString) {
          user = JSON.parse(userDataString);
        }
      } catch (e) {
        console.error('Failed to load token/user data from storage:', e);
      } finally {
        setUserToken(token);
        setUserData(user);
        setIsLoading(false);
      }
    };

    loadStoredData();
  }, []);

  return (
    <AuthContext.Provider value={{ userToken, userData, isLoading, signIn, signUp, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

// --- Screens ---
const LoadingScreen = () => {
  return (
    <View style={styles.container}>
      <ActivityIndicator size="large" color="#0000ff" />
      <Text style={styles.loadingText}>Loading user session...</Text>
    </View>
  );
};

const LoginScreen = ({ navigation }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const { signIn, isLoading } = useContext(AuthContext);

  const handleLogin = () => {
    signIn(username, password);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>
      <TextInput
        style={styles.input}
        placeholder="Username"
        value={username}
        onChangeText={setUsername}
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />
      <Button title={isLoading ? 'Logging in...' : 'Login'} onPress={handleLogin} disabled={isLoading} />
      <Button title="Don't have an account? Register" onPress={() => navigation.navigate('Register')} />
    </View>
  );
};

const RegisterScreen = ({ navigation }) => {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { signUp, isLoading } = useContext(AuthContext);

  const handleRegister = () => {
    signUp(username, email, password);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Register</Text>
      <TextInput
        style={styles.input}
        placeholder="Username"
        value={username}
        onChangeText={setUsername}
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        keyboardType="email-address"
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />
      <Button title={isLoading ? 'Registering...' : 'Register'} onPress={handleRegister} disabled={isLoading} />
      <Button title="Already have an account? Login" onPress={() => navigation.navigate('Login')} />
    </View>
  );
};

const HomeScreen = () => {
  const { signOut, userData, isLoading } = useContext(AuthContext);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome!</Text>
      {userData && (
        <View style={styles.userInfo}>
          <Text>Username: {userData.username}</Text>
          <Text>Email: {userData.email}</Text>
        </View>
      )}
      <Button title={isLoading ? 'Logging out...' : 'Logout'} onPress={signOut} disabled={isLoading} />
    </View>
  );
};

// --- Navigation Stacks ---
const AuthStack = createNativeStackNavigator();
const AppStack = createNativeStackNavigator();

const AuthNavigator = () => (
  <AuthStack.Navigator screenOptions={{ headerShown: false }}>
    <AuthStack.Screen name="Login" component={LoginScreen} />
    <AuthStack.Screen name="Register" component={RegisterScreen} />
  </AuthStack.Navigator>
);

const AppNavigator = () => (
  <AppStack.Navigator screenOptions={{ headerShown: false }}>
    <AppStack.Screen name="Home" component={HomeScreen} />
  </AppStack.Navigator>
);

// --- Root Navigator (switches between Auth and App stacks) ---
const RootNavigator = () => {
  const { userToken, isLoading } = useContext(AuthContext);

  if (isLoading) {
    return <LoadingScreen />;
  }

  return (
    <NavigationContainer>
      {userToken ? <AppNavigator /> : <AuthNavigator />}
    </NavigationContainer>
  );
};

// --- Main App Component ---
export default function App() {
  return (
    <AuthProvider>
      <RootNavigator />
    </AuthProvider>
  );
}

